1	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
2	import { RouterProvider } from "react-router-dom";
3	import { SessionProvider } from "@/features/session/context";
4	import { router } from "./router";
5	import type { ReactNode } from "react";
6	
7	const queryClient = new QueryClient({
8	  defaultOptions: {
9	    queries: {
10	      staleTime: 2000,
11	      retry: 1,
12	    },
13	  },
14	});
15	
16	export function Providers({ children }: { children?: ReactNode }) {
17	  return (
18	    <QueryClientProvider client={queryClient}>
19	      <SessionProvider>
20	        {children ?? <RouterProvider router={router} />}
21	      </SessionProvider>
22	    </QueryClientProvider>
23	  );
24	}
