1	import { useState } from "react";
2	import { Link } from "react-router-dom";
3	import { useMarkets } from "@/lib/query/hooks";
4	import { StatusBadge } from "@/components/ui/StatusBadge";
5	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
6	import { formatCurrency, timeUntil } from "@/lib/utils/format";
7	
8	const STATUSES = ["", "active", "resolved", "closed", "draft"] as const;
9	type StatusFilter = (typeof STATUSES)[number];
10	
11	export default function MarketList() {
12	  const [statusFilter, setStatusFilter] = useState<StatusFilter>("");
13	  const marketFilters = statusFilter ? { status: statusFilter } : undefined;
14	  const { data, isLoading, error } = useMarkets(marketFilters);
15	
16	  return (
17	    <div>
18	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-lg)" }}>
19	        <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>Markets</h1>
20	        <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center" }}>
21	          <Link
22	            to="/markets/new"
23	            style={{
24	              padding: "6px 14px",
25	              borderRadius: "var(--radius-sm)",
26	              background: "var(--color-primary)",
27	              color: "#fff",
28	              fontSize: "0.875rem",
29	              fontWeight: 600,
30	              textDecoration: "none",
31	            }}
32	          >
33	            + New Market
34	          </Link>
35	        <select
36	          value={statusFilter}
37	          onChange={(e) => setStatusFilter(e.target.value as StatusFilter)}
38	          style={{
39	            padding: "6px 12px",
40	            borderRadius: "var(--radius-sm)",
41	            border: "1px solid var(--color-border)",
42	            background: "var(--color-bg-surface)",
43	            color: "var(--color-text)",
44	            fontSize: "0.875rem",
45	          }}
46	        >
47	          {STATUSES.map((s) => (
48	            <option key={s} value={s}>{s || "All statuses"}</option>
49	          ))}
50	        </select>
51	        </div>
52	      </div>
53	
54	      {isLoading && <LoadingPage />}
55	      {error && <ErrorMessage message={error instanceof Error ? error.message : "Failed to load markets"} />}
56	
57	      {data && data.markets.length > 0 && (
58	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>
59	          <span>{data.markets.length} market{data.markets.length !== 1 ? "s" : ""}</span>
60	          <span>Total Volume: {formatCurrency(data.markets.reduce((s, m) => s + m.volume, 0))}</span>
61	          <span>Total Liquidity: {formatCurrency(data.markets.reduce((s, m) => s + m.liquidity, 0))}</span>
62	        </div>
63	      )}
64	
65	      {data && (
66	        <div style={{ display: "grid", gap: "var(--space-md)", gridTemplateColumns: "repeat(auto-fill, minmax(360px, 1fr))" }}>
67	          {data.markets.map((m) => (
68	            <Link
69	              key={m.id}
70	              to={`/markets/${m.id}`}
71	              style={{
72	                display: "block",
73	                padding: "var(--space-md)",
74	                borderRadius: "var(--radius-md)",
75	                background: "var(--color-bg-surface)",
76	                border: "1px solid var(--color-border)",
77	                textDecoration: "none",
78	                color: "inherit",
79	                transition: "border-color 0.15s",
80	              }}
81	              onMouseEnter={(e) => (e.currentTarget.style.borderColor = "var(--color-primary)")}
82	              onMouseLeave={(e) => (e.currentTarget.style.borderColor = "var(--color-border)")}
83	            >
84	              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "start", marginBottom: "var(--space-sm)" }}>
85	                <span style={{ fontWeight: 500, fontSize: "0.95rem" }}>{m.title}</span>
86	                <StatusBadge status={m.status} />
87	              </div>
88	              <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-sm)" }}>
89	                <span>Vol {formatCurrency(m.volume)}</span>
90	                <span>Liq {formatCurrency(m.liquidity)}</span>
91	                <span>{timeUntil(m.expires_at)}</span>
92	              </div>
93	            </Link>
94	          ))}
95	        </div>
96	      )}
97	
98	      {data && data.markets.length === 0 && (
99	        <div style={{ textAlign: "center", padding: "var(--space-xl)", color: "var(--color-text-muted)" }}>
100	          No markets found.
101	        </div>
102	      )}
103	    </div>
104	  );
105	}
