1	import { useState } from "react";
2	import { useParams } from "react-router-dom";
3	import { useMarket, useMarketEvents, useAccountRisk, useMarketPriceSubscription } from "@/lib/query/hooks";
4	import { useSession } from "@/features/session/context";
5	import { StatusBadge } from "@/components/ui/StatusBadge";
6	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
7	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
8	import { formatCurrency, timeUntil, truncateHash, formatRelativeTime } from "@/lib/utils/format";
9	import { AssumptionProvider } from "@/features/assumptions/AssumptionContext";
10	import { AssumptionPanel } from "@/features/assumptions/AssumptionPanel";
11	import { BayesNetGraph } from "@/features/graph/BayesNetGraph";
12	import { JunctionTreePanel } from "@/features/graph/JunctionTreePanel";
13	import { DiscussionThread } from "@/features/market/DiscussionThread";
14	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
15	import { EventTradePanel } from "@/features/trading/EventTradePanel";
16	import type { MarketEvent } from "@/lib/api/types";
17	
18	export default function MarketDetail() {
19	  const { marketId } = useParams<{ marketId: string }>();
20	  const { session, isConfigured } = useSession();
21	  const { data, isLoading, error } = useMarket(marketId!);
22	  const events = useMarketEvents(marketId!);
23	  const accountRisk = useAccountRisk(session.accountId);
24	  const isActiveMarket = data?.market.status === "active";
25	
26	  useMarketPriceSubscription(marketId ?? "", {
27	    enabled: Boolean(marketId) && !isLoading && !error && isActiveMarket,
28	  });
29	
30	  if (isLoading) return <LoadingPage />;
31	  if (error) return <ErrorMessage message={error instanceof Error ? error.message : "Market not found"} />;
32	  if (!data) return null;
33	
34	  const m = data.market;
35	
36	  return (
37	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
38	      <div>
39	        <div style={{ display: "flex", gap: "var(--space-md)", alignItems: "center", marginBottom: "var(--space-sm)" }}>
40	          <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>{m.title}</h1>
41	          <StatusBadge status={m.status} />
42	        </div>
43	        <p style={{ color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>{m.description}</p>
44	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.85rem", color: "var(--color-text-muted)" }}>
45	          <span>Volume: {formatCurrency(m.volume)}</span>
46	          <span>Liquidity: {formatCurrency(m.liquidity)}</span>
47	          <span>Expires: {timeUntil(m.expires_at)}</span>
48	        </div>
49	      </div>
50	
51	      <ProbabilityBar outcomes={m.outcomes} marginals={m.marginals} />
52	
53	      <PositionCard marketId={m.id} accountRisk={accountRisk.data} isConfigured={isConfigured} />
54	
55	      <ResolveMarketPanel market={m} />
56	
57	      {m.status === "active" && (
58	        <AssumptionProvider>
59	          <AssumptionPanel market={m} />
60	        </AssumptionProvider>
61	      )}
62	
63	      <EventTradePanel market={m} />
