133	export function useMarketPriceSubscription(marketId: string, opts?: { enabled?: boolean }) {
134	  const qc = useQueryClient();
135	  const enabled = opts?.enabled ?? true;
136	  const lastSeqRef = useRef<number>(-1);
137	  const reconnectAttemptRef = useRef(0);
138	  const reconnectTimerRef = useRef<number | null>(null);
139	
140	  useEffect(() => {
141	    if (!enabled || marketId.length === 0) {
142	      lastSeqRef.current = -1;
143	      reconnectAttemptRef.current = 0;
144	      if (reconnectTimerRef.current != null) {
145	        window.clearTimeout(reconnectTimerRef.current);
146	        reconnectTimerRef.current = null;
147	      }
148	      return;
149	    }
150	
151	    lastSeqRef.current = -1;
152	    reconnectAttemptRef.current = 0;
153	
154	    let socket: WebSocket | null = null;
155	    let effectClosed = false;
156	    let terminalStatus: MarketStatus | null = null;
157	
158	    const clearReconnectTimer = () => {
159	      if (reconnectTimerRef.current != null) {
160	        window.clearTimeout(reconnectTimerRef.current);
161	        reconnectTimerRef.current = null;
162	      }
163	    };
164	
165	    const scheduleReconnect = () => {
166	      clearReconnectTimer();
167	      const attempt = reconnectAttemptRef.current;
168	      const delay = Math.min(
169	        MAX_RECONNECT_DELAY_MS,
170	        INITIAL_RECONNECT_DELAY_MS * (2 ** attempt),
171	      );
172	      reconnectAttemptRef.current += 1;
173	      reconnectTimerRef.current = window.setTimeout(() => {
174	        if (effectClosed || terminalStatus !== null) {
175	          return;
176	        }
177	        refetchMarketRouteQueries(qc, marketId);
178	        connect();
179	      }, delay);
180	    };
181	
182	    const connect = () => {
183	      if (effectClosed || terminalStatus !== null) {
184	        return;
185	      }
186	
187	      socket = new WebSocket(api.getMarketPricesWebSocketUrl(marketId));
188	
189	      socket.addEventListener("open", () => {
190	        const reconnecting = reconnectAttemptRef.current > 0;
191	        reconnectAttemptRef.current = 0;
192	        clearReconnectTimer();
193	        if (reconnecting) {
194	          refetchMarketRouteQueries(qc, marketId);
195	        }
196	      });
197	
198	      socket.addEventListener("message", (event) => {
199	        if (typeof event.data !== "string") {
200	          return;
201	        }
202	
203	        let raw: unknown;
204	        try {
205	          raw = JSON.parse(event.data);
206	        } catch {
207	          return;
208	        }
209	
210	        const update = parseMarketPriceMessage(raw);
211	        if (!update || update.marketId !== marketId || update.seq <= lastSeqRef.current) {
212	          return;
213	        }
214	
215	        lastSeqRef.current = update.seq;
216	        qc.setQueryData<MarketDetailResponse>(queryKeys.market(marketId), (current) => {
217	          if (!current) {
218	            return current;
219	          }
220	
221	          return {
222	            ...current,
223	            market: {
224	              ...current.market,
225	              status: update.status,
226	              marginals: update.marginals,
227	              resolution: update.resolution ?? current.market.resolution,
228	              resolutionProbabilities: update.resolutionProbabilities ?? current.market.resolutionProbabilities,
229	            },
230	          };
231	        });
232	
233	        invalidateMarketDependentQueries(qc, marketId);
234	
235	        if (update.status !== "active") {
236	          terminalStatus = update.status;
237	          refetchMarketRouteQueries(qc, marketId);
238	          socket?.close();
239	        }
240	      });
241	
242	      socket.addEventListener("error", () => {
243	        socket?.close();
244	      });
245	
246	      socket.addEventListener("close", () => {
247	        socket = null;
248	        if (effectClosed) {
249	          return;
250	        }
251	
252	        if (terminalStatus !== null) {
253	          return;
254	        }
255	
256	        refetchMarketRouteQueries(qc, marketId);
257	        scheduleReconnect();
258	      });
259	    };
260	
261	    connect();
262	
263	    return () => {
264	      effectClosed = true;
265	      clearReconnectTimer();
266	      reconnectAttemptRef.current = 0;
267	      terminalStatus = null;
268	      socket?.close();
269	      socket = null;
270	    };
271	  }, [enabled, marketId, qc]);
272	}
